const baseUrl = env.get('STATE_URL') || 'http://127.0.0.1/api/state.php';
const raw = msg.payload;
if (!raw || typeof raw !== 'object' || Array.isArray(raw)) return null;
const emails = Array.isArray(raw.emails) ? raw.emails : [];
const phones = Array.isArray(raw.phones) ? raw.phones : [];
const email = emails.map(e => String(e || '').trim()).find(Boolean) || '';
const phone = phones.map(p => String(p || '').trim()).find(Boolean) || '';
msg.payload = { group_contact: { email, phone } };
msg.method = 'POST';
msg.url = baseUrl;
msg.headers = { 'Content-Type': 'application/json' };
return msg;

const baseUrl = env.get('STATE_URL') || 'http://127.0.0.1/api/state.php';
const cmd = String(msg.payload || '').trim().toLowerCase();
let patch = {};
if (cmd === 'start') {
  patch = { status: 'RUNNING' };
} else if (cmd === 'pause') {
  patch = { status: 'PAUSED' };
} else if (cmd === 'stop') {
  patch = {
    status: 'IDLE',
    quiz_state: {
      selected_answer: null,
      validation: 'idle',
      feedback_visible: false,
    },
  };
} else if (cmd === 'complete') {
  patch = { status: 'COMPLETED' };
} else if (cmd === 'reset') {
  patch = {
    status: 'IDLE',
    current_step: 1,
    quiz_state: {
      selected_answer: null,
      validation: 'idle',
      feedback_visible: false,
    },
  };
} else {
  return null;
}
msg.payload = patch;
msg.method = 'POST';
msg.url = baseUrl;
msg.headers = { 'Content-Type': 'application/json' };
return msg;

const baseUrl = env.get('STATE_URL') || 'http://127.0.0.1/api/state.php';
const raw = msg.payload;
let patch = {};

if (raw && typeof raw === 'object' && !Array.isArray(raw)) {
  if (raw.hardware) {
    patch = { hardware: raw.hardware };
  } else if (raw.display || raw.status || raw.quiz_state || raw.audio || raw.screens || raw.visitors || raw.group_contact) {
    patch = raw;
  } else {
    patch = {
      hardware: {
        last_sensor_event: {
          device: String(raw.device || 'esp32'),
          type: String(raw.type || 'event'),
          at: raw.at || new Date().toISOString()
        }
      }
    };
  }
} else {
  patch = {
    hardware: {
      last_sensor_event: {
        device: 'mqtt',
        type: String(raw),
        at: new Date().toISOString()
      }
    }
  };
}

msg.payload = patch;
msg.method = 'POST';
msg.url = baseUrl;
msg.headers = { 'Content-Type': 'application/json' };
return msg;
